def render_log_monitor():
    st.markdown("""
    <div class="page-banner">
        <h2>📋 Log Monitor</h2>
        <p>Real-time view of transaction logs, system logs, application logs and AWS events</p>
    </div>
    """, unsafe_allow_html=True)

    logs = generate_logs()

    c1, c2, c3 = st.columns(3)
    with c1:
        lvl_filter = st.multiselect("Log Level", ["ERROR","WARN","INFO","DEBUG"], default=["ERROR","WARN"])
    with c2:
        svc_filter = st.multiselect("Service", sorted(set(l["service"] for l in logs)), default=[])
    with c3:
        search_term = st.text_input("🔍 Search message", placeholder="keyword...")

    filtered = [l for l in logs
                if l["level"] in lvl_filter
                and (not svc_filter or l["service"] in svc_filter)
                and (not search_term or search_term.lower() in l["message"].lower())]

    level_colors = {"ERROR":"#C62828","WARN":"#F57C00","INFO":"#1565C0","DEBUG":"#2E7D32"}

    st.markdown(f"**{len(filtered)} entries**")
    for log in filtered[:100]:
        color = level_colors.get(log["level"], "#555")
        st.markdown(f"""
        <div style="background:white; border-left:4px solid {color};
                    padding:8px 14px; margin:3px 0; border-radius:0 6px 6px 0;
                    font-size:0.78rem; font-family:monospace;">
            <span style="color:{color}; font-weight:700;">[{log['level']}]</span>
            <span style="color:#94A3B8;"> {log['timestamp']}</span>
            <span style="color:#475569;"> [{log['service']}]</span>
            <span style="color:#1E293B;"> {log['message']}</span>
            <span style="color:#CBD5E1; float:right;">{log['request_id']}</span>
        </div>
        """, unsafe_allow_html=True)

    if st.button("🔄 Simulate New Log Ingestion"):
        new_log = {
            "timestamp": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            "level": random.choice(["ERROR","ERROR","WARN","INFO"]),
            "service": random.choice(["ndc-api","booking-engine","payment-gw"]),
            "message": random.choice(["Request timeout after 30000ms","Connection pool exhausted","Circuit breaker OPEN"]),
            "request_id": f"req-{random.randint(100000,999999)}",
        }
        st.session_state.logs.insert(0, new_log)
        if new_log["level"] == "ERROR":
            st.warning("⚠️ New ERROR detected — check Issues Dashboard")
        st.rerun()


