def render_aws_dashboard():
    st.markdown("""
    <div class="page-banner">
        <h2>☁️ AWS Infrastructure Dashboard</h2>
        <p>EC2, RDS, Lambda and ECS health overview</p>
    </div>
    """, unsafe_allow_html=True)

    aws = generate_aws_data()

    # EC2
    st.markdown("#### 🖥️ EC2 Instances")
    ec2_cols = st.columns(len(aws["ec2"]))
    for col, inst in zip(ec2_cols, aws["ec2"]):
        state_color = "#2E7D32" if inst["state"]=="running" else "#C62828"
        cpu_color   = "#C62828" if inst["cpu"]>80 else "#F57C00" if inst["cpu"]>60 else "#2E7D32"
        with col:
            st.markdown(f"""
            <div class="ac-card" style="border-top:4px solid {state_color};">
                <div style="font-weight:700; font-size:0.82rem; margin-bottom:4px;">{inst['name']}</div>
                <div style="font-size:0.7rem; color:#64748B;">{inst['type']}</div>
                <div style="margin-top:8px;">
                    <span style="background:{'#E8F5E9' if inst['state']=='running' else '#FFEBEE'};
                                 color:{state_color}; padding:2px 8px; border-radius:10px;
                                 font-size:0.68rem; font-weight:700;">● {inst['state'].upper()}</span>
                </div>
                {'<div style="margin-top:8px; font-size:0.72rem;">CPU: <b style="color:'+cpu_color+';">'+str(inst["cpu"])+'%</b> &nbsp; MEM: <b>'+str(inst["mem"])+'%</b></div>' if inst['state']=='running' else ''}
            </div>
            """, unsafe_allow_html=True)

    # RDS
    st.markdown("#### 🗄️ RDS Databases")
    rds_cols = st.columns(len(aws["rds"]))
    for col, db in zip(rds_cols, aws["rds"]):
        cpu_color = "#C62828" if db["cpu"]>70 else "#2E7D32"
        with col:
            st.markdown(f"""
            <div class="ac-card ac-card-blue">
                <div style="font-weight:700; font-size:0.82rem;">{db['id']}</div>
                <div style="font-size:0.7rem; color:#64748B;">{db['engine']} · {db['size']}</div>
                <div style="margin-top:8px; font-size:0.72rem;">
                    CPU: <b style="color:{cpu_color};">{db['cpu']}%</b> &nbsp;
                    Connections: <b>{db['connections']}</b>
                </div>
                <div style="margin-top:4px;">
                    <span style="background:#E8F5E9; color:#2E7D32; padding:2px 8px;
                                 border-radius:10px; font-size:0.68rem; font-weight:700;">● {db['state'].upper()}</span>
                </div>
            </div>
            """, unsafe_allow_html=True)

    # Lambda
    st.markdown("#### ⚡ Lambda Functions")
    lambda_df = pd.DataFrame(aws["lambda"])
    lambda_df["Error Rate"] = (lambda_df["errors"] / lambda_df["invocations"] * 100).round(2).astype(str) + "%"
    lambda_df["Avg Duration"] = lambda_df["duration_avg"].astype(str) + " ms"
    st.dataframe(lambda_df[["name","runtime","invocations","errors","Error Rate","Avg Duration"]]
                 .rename(columns={"name":"Function","runtime":"Runtime","invocations":"Invocations","errors":"Errors"}),
                 use_container_width=True, hide_index=True)

    # ECS
    st.markdown("#### 🐳 ECS Services")
    for svc in aws["ecs"]:
        health = svc["running"] == svc["desired"]
        cpu_color = "#C62828" if svc["cpu"]>75 else "#F57C00" if svc["cpu"]>50 else "#2E7D32"
        st.markdown(f"""
        <div class="ac-card" style="border-top:4px solid {'#2E7D32' if health else '#C62828'};">
            <div style="display:flex; justify-content:space-between; align-items:center;">
                <div>
                    <span style="font-weight:700;">{svc['service']}</span>
                    <span style="color:#64748B; font-size:0.75rem;"> · {svc['cluster']}</span>
                </div>
                <div style="font-size:0.75rem;">
                    Tasks: <b>{'✅' if health else '⚠️'} {svc['running']}/{svc['desired']}</b> &nbsp;
                    CPU: <b style="color:{cpu_color};">{svc['cpu']}%</b>
                </div>
            </div>
        </div>
        """, unsafe_allow_html=True)


