# TAB 5 — AI CHAT ASSISTANT
# ══════════════════════════════════════════════════════════════════════════════

def render_ai_chat():
    st.markdown("""
    <div class="page-banner">
        <h2>🤖 AI Assistant</h2>
        <p>Ask questions about issues, logs, infrastructure or request actions</p>
    </div>
    """, unsafe_allow_html=True)

    # Get API key
    api_key = None
    try:
        api_key = st.secrets.get("ANTHROPIC_API_KEY")
    except Exception:
        pass
    if not api_key:
        api_key = st.text_input("🔑 Anthropic API Key", type="password",
                                placeholder="sk-ant-...", key="chat_api_key")

    if not st.session_state.chat_history:
        st.session_state.chat_history = [{
            "role": "assistant",
            "content": (
                "👋 Hello! I'm your Air Canada Support System AI Assistant.\n\n"
                "I can help you with:\n"
                "- **Issue Analysis** — investigate detected incidents\n"
                "- **Log Interpretation** — explain error patterns\n"
                "- **AWS Health** — discuss infrastructure status\n"
                "- **Runbook Guidance** — suggest remediation steps\n"
                "- **Incident Summary** — generate reports for stakeholders\n\n"
                "What would you like to know?"
            )
        }]

    # Render chat history
    for msg in st.session_state.chat_history:
        if msg["role"] == "assistant":
            st.markdown(f'<div class="ai-bubble">🍁 <b>AC Support AI</b><br>{msg["content"]}</div>', unsafe_allow_html=True)
        else:
            st.markdown(f'<div class="user-bubble">{msg["content"]}</div>', unsafe_allow_html=True)

    # Build context from current issues
    issues = generate_issues()
    open_critical = [i for i in issues if i["criticality"]=="CRITICAL" and i["status"]!="Resolved"]
    open_high     = [i for i in issues if i["criticality"]=="HIGH" and i["status"]!="Resolved"]
    ctx_summary   = f"Current open CRITICAL issues: {len(open_critical)}. Open HIGH issues: {len(open_high)}."
    if open_critical:
        ctx_summary += f" Most urgent: {open_critical[0]['title']} in {open_critical[0]['source']}."

    user_input = st.chat_input("Ask about issues, logs, AWS health, or request a runbook...")
    if user_input:
        st.session_state.chat_history.append({"role":"user","content":user_input})
        if api_key and api_key.startswith("sk-ant-"):
            try:
                import anthropic
                client = anthropic.Anthropic(api_key=api_key)
                system_prompt = (
                    f"You are an expert Site Reliability Engineer for Air Canada's IT systems. "
                    f"You monitor NDC airline distribution systems, AWS infrastructure, and application logs. "
                    f"Current system context: {ctx_summary} "
                    f"Provide concise, actionable advice. Use emojis sparingly. "
                    f"When suggesting fixes, give specific commands or steps."
                )
                msgs = [{"role":m["role"],"content":m["content"]}
                        for m in st.session_state.chat_history if m["role"]!="assistant"
                        or m != st.session_state.chat_history[0]]
                resp = client.messages.create(
                    model="claude-sonnet-4-20250514",
                    max_tokens=1000,
                    system=system_prompt,
                    messages=msgs[-10:],
                )
                reply = resp.content[0].text
            except Exception as e:
                reply = f"⚠️ AI error: {str(e)}"
        else:
            # Demo responses
            demo = {
                "critical": f"🔴 There are {len(open_critical)} CRITICAL issues open. Most urgent: **{open_critical[0]['title'] if open_critical else 'None'}**. Recommend immediate escalation and Jira triage.",
                "aws":      "☁️ AWS overview: EC2 instances are mostly healthy. ECS payment-gw service has degraded task count (1/2 running) — recommend checking CloudWatch logs for OOM or crash loops.",
                "log":      "📋 Log pattern analysis: Main error cluster is TimeoutException in NDC API (32% of errors). Suggest checking downstream dependency health and increasing connection pool size.",
                "jira":     f"🎫 Jira status: {len(st.session_state.jira_tickets)} tickets created this session. All CRITICAL issues should have associated tickets.",
                "help":     "I can help with: issue triage, log analysis, AWS health checks, runbook guidance, and incident reports. Try asking 'summarize current critical issues' or 'what should I fix first?'",
            }
            q = user_input.lower()
            if any(w in q for w in ["critical","urgent","priority"]):  reply = demo["critical"]
            elif any(w in q for w in ["aws","ec2","rds","lambda","ecs"]): reply = demo["aws"]
            elif any(w in q for w in ["log","error","warn"]):            reply = demo["log"]
            elif any(w in q for w in ["jira","ticket"]):                  reply = demo["jira"]
            else:                                                           reply = demo["help"]

        st.session_state.chat_history.append({"role":"assistant","content":reply})
        st.rerun()

    if st.button("🗑️ Clear Chat"):
        st.session_state.chat_history = []
        st.rerun()


