    st.markdown("#### ➕ Add User (Demo)")
    c1, c2, c3 = st.columns(3)
    with c1: new_user = st.text_input("Username")
    with c2: new_role = st.selectbox("Role", ["Admin","Manager","Analyst","Viewer"])
    with c3: new_name = st.text_input("Full Name")
    if st.button("Add User") and new_user and new_name:
        st.success(f"✅ User '{new_user}' ({new_role}) added (demo — not persisted)")

    st.markdown("---")
    st.markdown("#### 🔐 Role Permissions")
    perms_data = [
        {"Role":"Admin",   "View Issues":"✅","Create Jira":"✅","Send Email":"✅","Resolve Issues":"✅","User Mgmt":"✅","Settings":"✅"},
        {"Role":"Manager", "View Issues":"✅","Create Jira":"✅","Send Email":"✅","Resolve Issues":"✅","User Mgmt":"❌","Settings":"✅"},
        {"Role":"Analyst", "View Issues":"✅","Create Jira":"✅","Send Email":"✅","Resolve Issues":"❌","User Mgmt":"❌","Settings":"❌"},
        {"Role":"Viewer",  "View Issues":"✅","Create Jira":"❌","Send Email":"❌","Resolve Issues":"❌","User Mgmt":"❌","Settings":"❌"},
    ]
    st.dataframe(pd.DataFrame(perms_data), use_container_width=True, hide_index=True)


