def main():
    if not st.session_state.authenticated:
        render_login()
        return

    render_sidebar()

    # Main header
    st.markdown(f"""
    <div style="display:flex; align-items:center; gap:16px; margin-bottom:20px;">
        <img src="data:image/png;base64,{AC_LOGO_B64}"
             style="height:48px; border-radius:4px;">
        <div>
            <div style="font-size:1.4rem; font-weight:800; color:{AC_DARK};">Air Canada Support System</div>
            <div style="font-size:0.78rem; color:#64748B;">Enterprise Log Monitoring & Incident Management · Powered by Infosys</div>
        </div>
    </div>
    """, unsafe_allow_html=True)

    # Tab navigation
    tabs = st.tabs([
        "🚨 Issues Dashboard",
        "📋 Log Monitor",
        "📊 Analytics",
        "☁️ AWS Dashboard",
        "🤖 AI Assistant",
        "🎫 Jira & Email Log",
        "⚙️ Settings",
        "👥 Users",
    ])

    with tabs[0]: render_issues_dashboard()
    with tabs[1]: render_log_monitor()
    with tabs[2]: render_analytics()
    with tabs[3]: render_aws_dashboard()
    with tabs[4]: render_ai_chat()
    with tabs[5]: render_notifications()
    with tabs[6]: render_settings()
    with tabs[7]: render_user_management()


if __name__ == "__main__":
    main()
